INSERT INTO photographers (id, name, surname, description, price, photo_path) VALUES
    ('692d3820-d762-436a-93ae-aaa1c7d2c1f5', 'Клод', 'Дебюсси', 'Мастер визуального импрессионизма, работающий с воздухом и тончайшими нюансами кадра. Он создаёт мягкие, словно текучие снимки, наполненные мечтательной атмосферой, где границы реальности размываются, уступая место чистому настроению.', 100000, '/images/placeholder.png'),
    ('c0db4f10-b720-4e2e-9a72-e3a4f30d3028', 'Кровосток', '', 'Мастера предельной честности и суровой эстетики, который видит красоту в прямых линиях и отсутствии лишнего пафоса. Группа Кровосток обеспечит вам такой же лаконичный кадр, как цветы в вазе, где за внешней простотой скрывается глубокий смысл и железная уверенность.', 150000, '/images/placeholder.png'),
    ('19b7720d-793a-4add-8207-a8baead65e2a', 'Канеки', 'Кен', 'Фотограф с особым взглядом на тёмную эстетику и сложный психологический портрет. Он виртуозно работает с глубокими тенями, скрытыми смыслами и острым контрастом, превращая внутреннюю борьбу и хрупкость момента в захватывающее визуальное искусство.', 65000, '/images/placeholder.png');
INSERT INTO equipment (id, title, description, price, photo_path) VALUES
	('9596154e-ee45-454a-adda-084fca722807', 'Камера', 'Профессиональные полнокадровые камеры — это сердце съёмочного процесса, гарантирующее исключительную детализацию и глубину цвета. Наша техника позволяет работать в самых разных жанрах, обеспечивая уверенность в каждом нажатии кнопки затвора. Высокое разрешение сенсоров сохраняет мельчайшие нюансы картинки, что критически важно для качественной крупноформатной печати.', 10000, '/images/placeholder.png'),
	('1251f03a-1851-491f-8071-0fe87547d35d', 'Штатив', 'Профессиональный штатив обеспечивает абсолютную стабильность камеры, что необходимо для ювелирной точности и идеально резких кадров. Прочные материалы и точные механизмы регулировки позволяют надёжно зафиксировать ракурс для работы с длинными выдержками, макросъемки или создания сложных композиций. Это незаменимый инструмент, когда важен каждый миллиметр точности.', 20000, '/images/placeholder.png'),
	('e46bd00d-b682-4adc-8320-aabd9ba4f045', 'Софтбокс', 'Этот модификатор является базовым инструментом для создания мягкого, направленного светового потока, который идеально подходит для портретной и предметной съёмки. Специальные рассеиватели деликатно сглаживают переходы между светом и тенью, делая текстуру визуально чище, а блики — аккуратными. Благодаря разным размерам софтбоксов, вы можете полностью контролировать мягкость рисунка в кадре.', 30000, '/images/placeholder.png'),
	('554c0677-d149-4e82-8c56-355c139e6ee1', 'Объектив', 'Парк топовой светосильной оптики с различным фокусным расстоянием даёт возможность реализовать любые творческие задачи — от масштабных интерьеров до крупных портретов. Высококлассные линзы обеспечивают бритвенную резкость в зоне фокуса и мягкое, художественное размытие фона. Наши объективы безупречно передают геометрию и объем, сохраняя естественную пластику кадра без искажений.', 15000, '/images/placeholder.png'),
	('60cab21d-31e8-4589-a145-5556172aa439', '6)Стойка для света', 'Устойчивые стойки — это фундамент вашей световой схемы, обеспечивающий безопасность тяжёлого оборудования и свободу творческих манёвров. Надёжные зажимы и продуманная конструкция позволяют надёжно зафиксировать источники света на нужной высоте или под сложным углом. Они легко перемещаются по залу, позволяя оперативно менять освещение и пробовать новые ракурсы в процессе работы.', 20000, '/images/placeholder.png'),
